#include<bits/stdc++.h>
using namespace std;
int n,tmax,a[10001];
bool check(int k)
{
	priority_queue<int,vector<int>,greater<int>> q;
	for(int i=1;i<=k;i++)
	{
		q.push(a[i]);
	}
	for(int i=k+1;i<=n;i++)
	{
		int t=q.top();
		q.pop();
		q.push(t+a[i]);
	}
	while(q.size()>1)
	{
		q.pop();
	}
	int temp=q.top();
	return temp<=tmax;
}
int main()
{
	scanf("%d%d",&n,&tmax);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	int l=1,r=n,best=-1;
	while(l<=r)
	{
		int mid=(l+r)/2;
		if(check(mid))
		{
			best=mid;
			r=mid-1;
		}
		else
		{
			l=mid+1;
		}
	}
	printf("%d",best);
	return 0;
}
